const BASE_URL = 'http://localhost:8080';

export async function getShows() {
  const res = await fetch(`${BASE_URL}/shows`);
  if (!res.ok) throw new Error('Erro ao buscar shows');
  return res.json();
}

export async function createShow(show) {
  const res = await fetch(`${BASE_URL}/shows`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(show),
  });
  if (!res.ok) {
    const err = await res.json();
    throw new Error(err.mensagem || 'Erro ao cadastrar show');
  }
  return res.json();
}

export async function updateShow(id, show) {
  const res = await fetch(`${BASE_URL}/shows/${id}`, {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(show),
  });
  if (!res.ok) {
    const err = await res.json();
    throw new Error(err.mensagem || 'Erro ao atualizar show');
  }
  return res.json();
}

export async function deleteShow(id) {
  const res = await fetch(`${BASE_URL}/shows/${id}`, { method: 'DELETE' });
  if (!res.ok) throw new Error('Erro ao deletar show');
}

export async function getFechamento(mes, ano) {
  const res = await fetch(`${BASE_URL}/fechamento?mes=${mes}&ano=${ano}`);
  if (!res.ok) throw new Error('Erro ao buscar fechamento');
  return res.json();
}
